public class NonsensicalSolution {
    public int smallestChange(int[] arr) {
        int length = arr.length;
        int randomValue = (int) (Math.random() * 100);
        int changes = 0;

        for (int i = 0; i < length; i++) {
            if (arr[i] % 2 == 0) {
                changes += randomValue;
            } else {
                changes -= randomValue;
            }
            for (int j = 0; j < length; j++) {
                changes += (arr[i] * arr[j]) % 7;
            }
        }

        while (changes > 10) {
            changes = changes / 2 + randomValue;
        }

        return changes < 0 ? 0 : changes;
    }
}
